constraint_dry_run_no_writes.cmd:
tmp=$(mktemp /tmp/test_dry_run_XXXXXX.rs); printf 'unsafe fn foo(p: *mut Foo) {
  let x = (*p).field;
  let y = (*p).field;
  let z = (*p).field;
}' > "$tmp"; before=$(md5sum "$tmp" | awk '{print $1}'); python /unsafe_rust_fixer/unsafe-rust-fixer.py --match-patterns=raw_ptr_deref_field_chain --fix --dry-run "$tmp"; rc=$?; after=$(md5sum "$tmp" | awk '{print $1}'); rm -f "$tmp"; [ "$before" = "$after" ] || { echo "FAIL: --dry-run modified the file"; exit 1; }; [ $rc -eq 1 ] || { echo "FAIL: --dry-run must exit 1 when changes would be made (got exit $rc)"; exit 1; }

constraint_no_verbose_output_without_fla.cmd:
tmp=$(mktemp /tmp/test_verbose_XXXXXX.rs); printf 'unsafe fn foo(p: *mut Foo) {
  let x = (*p).field;
  let y = (*p).field;
  let z = (*p).field;
}' > "$tmp"; output=$(python /unsafe_rust_fixer/unsafe-rust-fixer.py --match-patterns=raw_ptr_deref_field_chain --fix --dry-run "$tmp" 2>&1); rm -f "$tmp"; echo "$output" | grep -qF 'Matched:' && { echo 'FAIL: verbose output Matched: printed without --verbose'; exit 1; }; echo "$output" | grep -qF 'Fixed' && { echo 'FAIL: verbose output Fixed printed without --verbose'; exit 1; }; echo "$output" | grep -qF 'Would update' && { echo 'FAIL: verbose output Would update printed without --verbose'; exit 1; }; echo "$output" | grep -qF 'Fixes skipped (dry-run):' || { echo 'FAIL: dry-run summary line missing'; exit 1; }

constraint_needless_return_fixed.cmd:
tmp=$(mktemp /tmp/test_clippy_XXXXXX.rs); printf "pub fn get_val() -> i32 {
    let x = 42;
    return x;
}
" > "$tmp"; python /unsafe_rust_fixer/unsafe-rust-fixer.py --match-patterns=clippy_warning_patterns --fix "$tmp" > /dev/null 2>&1; result=$(cat "$tmp"); rm -f "$tmp"; echo "$result" | grep -q "return x" && { echo "FAIL: needless_return was not removed"; exit 1; }; echo "OK: needless_return fixed"

constraint_assign_op_fixed.cmd:
tmp=$(mktemp /tmp/test_clippy_XXXXXX.rs); printf "pub fn update(mut a: u32, mask: u32) -> u32 {
    a = a & mask;
    a = a + 1;
    a
}
" > "$tmp"; python /unsafe_rust_fixer/unsafe-rust-fixer.py --match-patterns=clippy_warning_patterns --fix "$tmp" > /dev/null 2>&1; result=$(cat "$tmp"); rm -f "$tmp"; echo "$result" | grep -qE "a &= |a \+= " || { echo "FAIL: assign_op_pattern not rewritten to compound assignment"; exit 1; }; echo "OK: assign_op_pattern fixed"

constraint_collapsible_else_if_fixed.cmd:
tmp=$(mktemp /tmp/test_clippy_XXXXXX.rs); printf "pub fn cmp(a: i32, b: i32) -> i32 {
    if a > b {
        1
    } else {
        if a == b {
            0
        } else {
            -1
        }
    }
}
" > "$tmp"; python /unsafe_rust_fixer/unsafe-rust-fixer.py --match-patterns=clippy_warning_patterns --fix "$tmp" > /dev/null 2>&1; result=$(cat "$tmp"); rm -f "$tmp"; echo "$result" | grep -q "else if a == b" || { echo "FAIL: collapsible_else_if not collapsed to else if"; exit 1; }; echo "OK: collapsible_else_if fixed"
